def _has(text, *needles):
    return any(needle in text for needle in needles)


def triage_ticket(message, inventory=None):
    inventory = inventory or {}
    text = message.lower()
    category = "general"
    skill = "general"
    parts = []
    urgency = "scheduled"
    risk = 20

    if _has(text, "freezer", "fridge", "cooler", "walk-in"):
        category = skill = "refrigeration"
        if _has(text, "freezer", "down", "losing stock"):
            parts.append("compressor")
        if _has(text, "noise", "loud"):
            parts.append("fan_motor")
    elif _has(text, "heat", "hvac", "filter", "thermostat"):
        category = skill = "hvac"
        if _has(text, "filter", "annual"):
            parts.append("filter")
        else:
            parts.append("thermostat")
    elif _has(text, "sink", "drain", "pipe", "leak"):
        category = skill = "plumbing"
        parts.append("trap")
    elif _has(text, "breaker", "lights", "flicker", "electrical"):
        category = skill = "electrical"
        parts.append("breaker")

    if _has(text, "down", "losing stock", "toddlers", "daycare", "in an hour", "emergency"):
        urgency = "emergency"
        risk = 95 if category == "refrigeration" else 90
    elif _has(text, "today", "tripping", "flicker", "noise", "loud", "still cold"):
        urgency = "same_day"
        risk = 72 if category == "electrical" else 65
    elif _has(text, "annual", "no rush", "next week"):
        urgency = "scheduled"
        risk = 25 if category == "hvac" else 30

    if category == "refrigeration" and urgency == "scheduled":
        risk = max(risk, 55)
    if category == "electrical" and urgency != "emergency":
        urgency = "same_day"
        risk = max(risk, 70)

    available_parts = [part for part in parts if inventory.get(part, 0) > 0]
    required_parts = available_parts or parts

    return {
        "category": category,
        "urgency": urgency,
        "required_skill": skill,
        "required_parts": required_parts,
        "risk_score": max(0, min(100, int(risk))),
        "customer_eta_required": urgency in {"emergency", "same_day"},
    }
